ybtS8UHfmX2KHqhAtuvvjwbmuGvapb7Hz_e9s9f3xN5SPV7VC43cJIryLMorzXw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"• La très grande terrasse idéalement exposée offre un ensoleillement optimal l''après-midi, parfait pour les fins de journée d''été.\n• Le service est souvent cité parmi les meilleurs du quartier pour sa bonne humeur authentique.\n• Il est particulièrement agréable de venir boire sa pinte blonde à 3€ pendant les 7 d''Happy Hour XXL","specials":{"cuisine":["Bœuf bourguignon","Dindo burger","Tartare de bœuf","Entrecôte XL"],"drinks":["Pinte (6.10€, HH 3.00€)","Verre de vin (4.90€)"],"must_eat":"Brasserie traditionnelle. Foncez sur le Dindo Burger ou le classique bœuf bourguignon avec sa purée régressive.","must_drink":"Remarquable Happy Hour XXL (17h-00h) avec la pinte de blonde à 3€. Misez aussi sur les bouteilles de vin abordables."},"expert_catchline":"Une brasserie colorée à l''accueil généreux et à la belle terrasse ensoleillée."}', 'Située idéalement sur l''avenue de Laumière, cette brasserie traditionnelle offre un cadre hybride parfait entre le restaurant convivial et le bistrot de quartier. La décoration originale et colorée donne un vrai cachet au lieu, tandis que la grande terrasse permet de profiter des rayons du soleil. La carte généreuse navigue entre grands classiques de la cuisine bourgeoise et burgers gourmands, le tout servi par une équipe souriante et chaleureuse.', '• La très grande terrasse idéalement exposée offre un ensoleillement optimal l''après-midi, parfait pour les fins de journée d''été.
• Le service est souvent cité parmi les meilleurs du quartier pour sa bonne humeur authentique.
• Il est particulièrement agréable de venir boire sa pinte blonde à 3€ pendant les 7 d''Happy Hour XXL', 'Laumière', '[5]', '[]', 'ChIJYwcxFgBt5kcRVnUOA55YmQ8', NULL);
INSERT INTO places_fts VALUES ('poi-chez-maman', 'Chez Maman', 'restaurant', 'brasserie bar', '34 Av. de Laumière', '', 'Située idéalement sur l''avenue de Laumière, cette brasserie traditionnelle offre un cadre hybride parfait entre le restaurant convivial et le bistrot de quartier. La décoration originale et colorée donne un vrai cachet au lieu, tandis que la grande terrasse permet de profiter des rayons du soleil. La carte généreuse navigue entre grands classiques de la cuisine bourgeoise et burgers gourmands, le tout servi par une équipe souriante et chaleureuse.');
INSERT INTO places VALUES ('poi-013', 'Café A', 'cafe-a', 'café', 'cafe-jardin', 'chill', 48.875386, 2.360012, 10, '148 Rue du Faubourg Saint-Martin', '#8ccaf7', 'pin', 1, 4.2, 0, 'https://upload.wikimedia.org/wikipedia/commons/c/c9/Jardin_Villemin_-_Couvent_des_R%C3%A9collets.jpg', NULL, 3.5, 0, '€', NULL, NULL, NULL, 3.5, 16, 50, '{"chill":24,"festif":4,"culturel":7.5}', '{}', '["café","cafe-jardin"]', '{"standard":"","display":"","detailed":""}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":20,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":3.5,"dish_price":16,"last_updated":"2025-01-15","menu_items":[]}', '{"hero":"https://upload.wikimedia.org/wikipedia/commons/c/c9/Jardin_Villemin_-_Couvent_des_R%C3%A9collets.jpg","gallery":[]}', '[]', NULL, '{"insider_tip":"L''adresse préférée des locaux, loin des foules habituelles.","specials":{"cuisine":[],"drinks":[]}}', 'Installé dans l''ancien couvent des Récollets (actuelle Maison de l''Architecture), près de la Gare de l''Est, le Café A possède l''une des plus belles cours intérieures secrètes de Paris. On boit un verre sous les arcades ou allongé dans des transats sur le gravier blanc, à l''ombre de vieux arbres. C''est calme, vaste, et inattendu dans ce quartier dense. Un havre de paix architectural parfait pour les beaux jours.', 'L''adresse préférée des locaux, loin des foules habituelles.', 'Gare de l''Est', '[4,5,7]', '[]', NULL, NULL);
INSERT INTO places_fts VALUES ('poi-013', 'Café A', 'café', 'cafe-jardin', '148 Rue du Faubourg Saint-Martin', '', 'Installé dans l''ancien couvent des Récollets (actuelle Maison de l''Architecture), près de la Gare de l''Est, le Café A possède l''une des plus belles cours intérieures secrètes de Paris. On boit un verre sous les arcades ou allongé dans des transats sur le gravier blanc, à l''ombre de vieux arbres. C''est calme, vaste, et inattendu dans ce quartier dense. Un havre de paix architectural parfait pour les beaux jours.');
