INSERT INTO places_fts VALUES ('poi-frederic-simonin-restaurant', 'Frédéric Simonin', 'restaurant', 'Gastronomique Michelin-starred Classique Produit', '25 Rue Bayen, 75017 Paris, France', '', 'Frédéric Simonin, Meilleur Ouvrier de France, livre une partition gastronomique impeccable dans un écrin sobre et chic de la Plaine Monceau. Étoilée au Guide Michelin, sa table célèbre le produit brut avec une technique virtuose et des assaisonnements d''une justesse rare. C''est la quintessence du raffinement français : discret, souverain et profondément axé sur l''émotion gustative.');
